    18→import com.formfiller.data.Profile
    19→import com.formfiller.ime.FieldExtractor
    20→import kotlinx.coroutines.launch
    21→
    22→class MainActivity : AppCompatActivity() {
    23→
    24→    private lateinit var db: AppDatabase
    25→    private lateinit var spProfile: Spinner
    26→    private lateinit var rvFields: RecyclerView
    27→    private lateinit var etInput: EditText
    28→    private lateinit var etLabel: EditText
    29→    private lateinit var etValue: EditText
    30→
    31→    private var profiles = mutableListOf<Profile>()
    32→    private var fields = mutableListOf<Field>()
    33→    private val currentProfileId get() = profiles.getOrNull(spProfile.selectedItemPosition)?.id
    34→
    35→    override fun onCreate(savedInstanceState: Bundle?) {
    36→        super.onCreate(savedInstanceState)
    37→        setContentView(R.layout.activity_main)
    38→
    39→        db = AppDatabase.get(this)
    40→        spProfile = findViewById(R.id.spProfile)
    41→        rvFields = findViewById(R.id.rvFields)
    42→        etInput = findViewById(R.id.etInput)
    43→        etLabel = findViewById(R.id.etLabel)
    44→        etValue = findViewById(R.id.etValue)
    45→
    46→        rvFields.layoutManager = LinearLayoutManager(this)
    47→
    48→        findViewById<Button>(R.id.btnEnableIME).setOnClickListener { enableIME() }
    49→        findViewById<Button>(R.id.btnEnableAutofill).setOnClickListener { enableAutofill() }
    50→        findViewById<ImageButton>(R.id.btnAddProfile).setOnClickListener { addProfile() }
    51→        findViewById<ImageButton>(R.id.btnDeleteProfile).setOnClickListener { deleteProfile() }
    52→        findViewById<Button>(R.id.btnExtract).setOnClickListener { extractFields() }
    53→        findViewById<Button>(R.id.btnAdd).setOnClickListener { addField() }
    54→
    55→        spProfile.onItemSelectedListener = object : AdapterView.OnItemSelectedListener {
    56→            override fun onItemSelected(p: AdapterView<*>?, v: android.view.View?, pos: Int, id: Long) = loadFields()
    57→            override fun onNothingSelected(p: AdapterView<*>?) {}
    58→        }
    59→
    60→        loadProfiles()
    61→    }
    62→
    63→    private fun enableIME() {
    64→        val imm = getSystemService(INPUT_METHOD_SERVICE) as InputMethodManager
    65→        val enabled = imm.enabledInputMethodList.any { it.packageName == packageName }
    66→        if (!enabled) {
    67→            startActivity(Intent(Settings.ACTION_INPUT_METHOD_SETTINGS))
    68→            Toast.makeText(this, "请在设置中启用「智能填表输入法」", Toast.LENGTH_LONG).show()
    69→        } else {
    70→            imm.showInputMethodPicker()
    71→        }
    72→    }
    73→
    74→    private fun enableAutofill() {
    75→        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
    76→            val afm = getSystemService(AutofillManager::class.java)
    77→            if (afm.hasEnabledAutofillServices()) {
    78→                Toast.makeText(this, "自动填充服务已启用", Toast.LENGTH_SHORT).show()
    79→            } else {
    80→                val intent = Intent(Settings.ACTION_REQUEST_SET_AUTOFILL_SERVICE).apply {
    81→                    data = android.net.Uri.parse("package:$packageName")
    82→                }
    83→                startActivity(intent)
    84→                Toast.makeText(this, "请选择「智能填表自动填充」", Toast.LENGTH_LONG).show()
    85→            }
    86→        } else {
    87→            Toast.makeText(this, "自动填充需要 Android 8.0 以上", Toast.LENGTH_SHORT).show()
    88→        }
    89→    }
    90→
    91→    private fun loadProfiles() {
    92→        lifecycleScope.launch {
    93→            profiles.clear()
    94→            profiles.addAll(db.profileDao().getAll())
    95→            if (profiles.isEmpty()) {
    96→                val id = db.profileDao().insert(Profile(name = "默认档案"))
    97→                profiles.add(Profile(id = id, name = "默认档案"))
    98→            }
    99→            spProfile.adapter = ArrayAdapter(
   100→                this@MainActivity, android.R.layout.simple_spinner_dropdown_item,
   101→                profiles.map { it.name }
   102→            )
   103→            loadFields()
   104→        }
   105→    }
   106→
   107→    private fun loadFields() {
   108→        val pid = currentProfileId ?: return
   109→        lifecycleScope.launch {
   110→            fields.clear()
   111→            fields.addAll(db.fieldDao().getByProfile(pid))
   112→            rvFields.adapter = FieldRowAdapter(fields,
   113→                onDelete = { f ->
   114→                    lifecycleScope.launch {
   115→                        db.fieldDao().delete(f)
   116→                        fields.remove(f)
   117→                        rvFields.adapter?.notifyDataSetChanged()
   118→                    }
   119→                }
   120→            )
   121→        }
   122→    }
   123→
   124→    private fun addProfile() {
   125→        val et = EditText(this).apply { hint = "档案名称" }
   126→        AlertDialog.Builder(this).setTitle("新建档案").setView(et)
   127→            .setPositiveButton("确定") { _, _ ->
   128→                val name = et.text.toString().trim()
   129→                if (name.isNotEmpty()) {
   130→                    lifecycleScope.launch {
   131→                        db.profileDao().insert(Profile(name = name))
   132→                        loadProfiles()
   133→                    }
   134→                }
   135→            }.show()
